INSERT IGNORE INTO `#__j2commerce_invoicetemplates` (`j2commerce_invoicetemplate_id`, `title`, `invoice_type`, `orderstatus_id`, `group_id`, `paymentmethod`, `body`, `body_json`, `body_source`, `body_source_file`, `custom_css`, `language`, `enabled`, `ordering`)
VALUES  (1, 'Packing Slip', 'packingslip', '*', '1', '*', '<!-- J2Commerce Packing Slip - Modern Template -->
<table style="background-color: #f8fafc; font-family: Arial, Helvetica, sans-serif;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 20px 10px;" align="center">
<table class="slip-container" style="max-width: 600px; width: 100%; background-color: #ffffff;" border="0" width="600" cellspacing="0" cellpadding="0"><!-- Logo Bar -->
<tbody>
<tr>
<td style="padding: 20px 30px; background-color: #ffffff; border-radius: 12px 12px 0 0; text-align: center;">[IF:STORE_LOGO_URL] <img style="display: block; margin: 0 auto; border: 0; height: [LOGO_MAX_HEIGHT]px; width: auto;" src="[STORE_LOGO_URL]" alt="[SITENAME]"> [/IF:STORE_LOGO_URL] [IFNOT:STORE_LOGO_URL] <span style="font-size: 22px; font-weight: bold; color: [accent_color];">[SITENAME]</span> [/IFNOT:STORE_LOGO_URL]</td>
</tr>
<!-- Packing Slip Header Banner -->
<tr>
<td style="background-color: [accent_color]; padding: 28px 30px; text-align: center;"><!-- Box Icon -->
<table border="0" cellspacing="0" cellpadding="0" align="center">
<tbody>
<tr>
<td style="width: 50px; height: 50px; background-color: rgba(255,255,255,0.2); border-radius: 50%; text-align: center; vertical-align: middle; font-size: 24px; color: #ffffff;">📦</td>
</tr>
</tbody>
</table>
<h1 style="margin: 14px 0 4px 0; font-size: 24px; font-weight: bold; color: #ffffff; text-transform: uppercase; letter-spacing: 1px;">Packing Slip</h1>
<p style="margin: 0; font-size: 14px; color: rgba(255,255,255,0.85);">Order #[ORDERID] • [ORDERDATE]</p>
</td>
</tr>
<!-- Ship To & Order Info Cards -->
<tr>
<td class="mobile-padding" style="padding: 20px 20px 0 20px;">
<table border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr><!-- Ship To -->
<td class="address-col" style="width: 60%; vertical-align: top; padding-right: 8px;">
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Ship To</td>
</tr>
<tr>
<td style="padding: 14px 18px; font-size: 14px; color: #1f2937; line-height: 1.6;"><strong style="font-size: 15px;">[SHIPPING_FIRSTNAME] [SHIPPING_LASTNAME]</strong> [IF:SHIPPING_COMPANY]<br>[SHIPPING_COMPANY][/IF:SHIPPING_COMPANY]<br>[SHIPPING_ADDRESS_1] [IF:SHIPPING_ADDRESS_2]<br>[SHIPPING_ADDRESS_2][/IF:SHIPPING_ADDRESS_2]<br>[SHIPPING_CITY], [SHIPPING_STATE] [SHIPPING_ZIP]<br>[SHIPPING_COUNTRY] [IF:SHIPPING_PHONE]<br>📞 [SHIPPING_PHONE][/IF:SHIPPING_PHONE]</td>
</tr>
</tbody>
</table>
</td>
<!-- Order Details -->
<td class="address-col" style="width: 40%; vertical-align: top; padding-left: 8px;">
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Order Details</td>
</tr>
<tr>
<td style="padding: 14px 18px; font-size: 13px; color: #1f2937; line-height: 1.8;"><strong>Order:</strong> #[ORDERID]<br><strong>Date:</strong> [ORDERDATE]<br><strong>Status:</strong> [ORDERSTATUS] [IF:SHIPPING_METHOD]<br><strong>Ship via:</strong> [SHIPPING_METHOD][/IF:SHIPPING_METHOD] [IF:SHIPPING_TRACKING_ID]<br><strong>Tracking:</strong> [SHIPPING_TRACKING_ID][/IF:SHIPPING_TRACKING_ID]</td>
</tr>
</tbody>
</table>
</td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Items Card (NO PRICES) -->
<tr>
<td class="mobile-padding" style="padding: 16px 20px;">[ITEMS_LOOP] [/ITEMS_LOOP]
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;" border="0" width="100%" cellspacing="0" cellpadding="0"><!-- Card Header -->
<tbody>
<tr>
<td style="padding: 16px 20px; border-bottom: 1px solid #f3f4f6;" colspan="4"><span style="font-size: 15px; font-weight: bold; color: #1f2937;">Items to Pack</span></td>
</tr>
<!-- Column Headers -->
<tr>
<td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;" colspan="2">Product</td>
<td style="padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 50px;">Qty</td>
<td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 70px;">Packed ✓</td>
</tr>
<!-- Items -->
<tr>
<td style="padding: 12px 0 12px 20px; border-top: 1px solid #f3f4f6; vertical-align: top; width: 60px;">[IF:ITEM_IMAGE] <img class="item-img" style="border-radius: 6px; object-fit: cover; display: block; border: 1px solid #f3f4f6;" src="[ITEM_IMAGE]" alt="[ITEM_NAME]" width="50" height="50"> [/IF:ITEM_IMAGE] [IFNOT:ITEM_IMAGE]
<table border="0" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="width: 50px; height: 50px; background-color: #f3f4f6; border-radius: 6px; text-align: center; vertical-align: middle; font-size: 20px; color: #d1d5db;">📦</td>
</tr>
</tbody>
</table>
[/IFNOT:ITEM_IMAGE]</td>
<td style="padding: 12px 10px; border-top: 1px solid #f3f4f6; vertical-align: top;"><span style="font-size: 14px; font-weight: 600; color: #1f2937;">[ITEM_NAME]</span> [IF:ITEM_SKU]<br><span style="font-size: 12px; color: #9ca3af;">SKU: [ITEM_SKU]</span>[/IF:ITEM_SKU] [IF:ITEM_OPTIONS]<br><span style="font-size: 12px; color: #6b7280;">[ITEM_OPTIONS]</span>[/IF:ITEM_OPTIONS] [IF:ITEM_WEIGHT]<br><span style="font-size: 12px; color: #9ca3af;">Weight: [ITEM_WEIGHT]</span>[/IF:ITEM_WEIGHT]</td>
<td style="padding: 12px 10px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top; font-size: 18px; font-weight: bold; color: #1f2937;">[ITEM_QTY]</td>
<td style="padding: 12px 20px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top;"><!-- Checkbox placeholder for warehouse staff -->
<table border="0" cellspacing="0" cellpadding="0" align="center">
<tbody>
<tr>
<td style="width: 24px; height: 24px; border: 2px solid #d1d5db; border-radius: 4px; background-color: #ffffff;"> </td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Total Items Count -->
<tr>
<td style="padding: 14px 20px; background-color: #f9fafb; border-top: 1px solid #e5e7eb;" colspan="4">
<table border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="font-size: 13px; font-weight: bold; color: #6b7280;">Total Weight</td>
<td style="font-size: 13px; font-weight: bold; color: #1f2937; text-align: right;">[SHIPPING_TOTAL_WEIGHT]</td>
</tr>
</tbody>
</table>
</td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Customer Note -->
<tr>
<td class="mobile-padding" style="padding: 0;">[IF:CUSTOMER_NOTE]
<table border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 0 20px 16px 20px;">
<table style="background-color: #fffbeb; border: 1px solid #fde68a; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; font-size: 13px; font-weight: bold; color: #92400e; text-transform: uppercase; letter-spacing: 0.5px;">⚠ Customer Note</td>
</tr>
<tr>
<td style="padding: 0 18px 14px 18px; font-size: 14px; color: #78350f; line-height: 1.5;">[CUSTOMER_NOTE]</td>
</tr>
</tbody>
</table>
</td>
</tr>
</tbody>
</table>
[/IF:CUSTOMER_NOTE]</td>
</tr>
