<tr>
<td class="mobile-padding" style="padding: 0 20px 20px 20px;">
<table style="background-color: #f9fafb; border: 1px solid #e5e7eb; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; border-bottom: 1px solid #e5e7eb; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Fulfillment</td>
</tr>
<tr>
<td style="padding: 18px;">
<table border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
