        (2, 'Invoice', 'invoice', '*', '1', '*', '<!-- J2Commerce Invoice - Modern Template -->
<table style="background-color: #f8fafc; font-family: Arial, Helvetica, sans-serif;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 20px 10px;" align="center">[IF:PAYMENT_METHOD] [/IF:PAYMENT_METHOD] [IF:CUSTOMER_NOTE] [/IF:CUSTOMER_NOTE] [HOOK:AFTER_INVOICE_BODY]
<table class="inv-container" style="max-width: 600px; width: 100%; background-color: #ffffff;" border="0" width="600" cellspacing="0" cellpadding="0"><!-- Logo Bar -->
<tbody>
<tr>
<td style="padding: 20px 30px; background-color: #ffffff; border-radius: 12px 12px 0 0; text-align: center;">[IF:STORE_LOGO_URL] <img style="display: block; margin: 0 auto; border: 0; height: [LOGO_MAX_HEIGHT]px; width: auto;" alt="[SITENAME]"  src="[STORE_LOGO_URL]"> [/IF:STORE_LOGO_URL] [IFNOT:STORE_LOGO_URL] <span style="font-size: 22px; font-weight: bold; color: [accent_color];">[SITENAME]</span> [/IFNOT:STORE_LOGO_URL]</td>
</tr>
<!-- Invoice Header Banner -->
<tr>
<td style="background-color: [accent_color]; padding: 28px 30px; text-align: center;">
<table border="0" cellspacing="0" cellpadding="0" align="center">
<tbody>
<tr>
<td style="width: 50px; height: 50px; background-color: rgba(255,255,255,0.2); border-radius: 50%; text-align: center; vertical-align: middle; font-size: 24px; color: #ffffff;">📄</td>
</tr>
</tbody>
</table>
<h1 style="margin: 14px 0 4px 0; font-size: 24px; font-weight: bold; color: #ffffff; text-transform: uppercase; letter-spacing: 1px;">Invoice</h1>
<p style="margin: 0; font-size: 14px; color: rgba(255,255,255,0.85);">Order #[ORDERID] • [ORDERDATE]</p>
</td>
</tr>
<!-- Billing & Shipping Address Cards -->
<tr>
<td class="mobile-padding" style="padding: 20px 20px 0 20px;">[IF:SHIPPING_FIRSTNAME] [/IF:SHIPPING_FIRSTNAME]
<table border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr><!-- Bill To -->
<td class="address-col" style="width: 50%; vertical-align: top; padding-right: 8px;">
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Bill To</td>
</tr>
<tr>
<td style="padding: 14px 18px; font-size: 14px; color: #1f2937; line-height: 1.6;"><strong style="font-size: 15px;">[BILLING_FIRSTNAME] [BILLING_LASTNAME]</strong> [IF:BILLING_COMPANY]<br>[BILLING_COMPANY][/IF:BILLING_COMPANY]<br>[BILLING_ADDRESS_1] [IF:BILLING_ADDRESS_2]<br>[BILLING_ADDRESS_2][/IF:BILLING_ADDRESS_2]<br>[BILLING_CITY], [BILLING_STATE] [BILLING_ZIP]<br>[BILLING_COUNTRY] [IF:BILLING_PHONE]<br>📞 [BILLING_PHONE][/IF:BILLING_PHONE] [IF:BILLING_EMAIL]<br>✉ [BILLING_EMAIL][/IF:BILLING_EMAIL]</td>
</tr>
</tbody>
</table>
</td>
<!-- Ship To -->
<td class="address-col" style="width: 50%; vertical-align: top; padding-left: 8px;">
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Ship To</td>
</tr>
<tr>
<td style="padding: 14px 18px; font-size: 14px; color: #1f2937; line-height: 1.6;"><strong style="font-size: 15px;">[SHIPPING_FIRSTNAME] [SHIPPING_LASTNAME]</strong> [IF:SHIPPING_COMPANY]<br>[SHIPPING_COMPANY][/IF:SHIPPING_COMPANY]<br>[SHIPPING_ADDRESS_1] [IF:SHIPPING_ADDRESS_2]<br>[SHIPPING_ADDRESS_2][/IF:SHIPPING_ADDRESS_2]<br>[SHIPPING_CITY], [SHIPPING_STATE] [SHIPPING_ZIP]<br>[SHIPPING_COUNTRY] [IF:SHIPPING_PHONE]<br>📞 [SHIPPING_PHONE][/IF:SHIPPING_PHONE]</td>
</tr>
</tbody>
</table>
</td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Items Table WITH Prices -->
<tr>
<td class="mobile-padding" style="padding: 16px 20px;">[ITEMS_LOOP] [/ITEMS_LOOP]
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 16px 20px; border-bottom: 1px solid #f3f4f6;" colspan="5"><span style="font-size: 15px; font-weight: bold; color: #1f2937;">Order Items</span></td>
</tr>
<tr>
<td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;" colspan="2">Product</td>
<td style="padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 50px;">Qty</td>
<td style="padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: right; width: 80px;">Price</td>
