        (3, 'Receipt (Thermal)', 'receipt', '*', '1', '*', '<!-- J2Commerce Receipt - Thermal / POS Template -->
<div class="thermal-receipt"><!-- Store Header -->
<div class="center bold" style="font-size: 16px; margin-bottom: 2px;">[SITENAME]</div>
<div class="center" style="font-size: 11px; color: #555; margin-bottom: 4px;">[SITEURL]</div>
<hr class="double-dashed">
<div class="center bold" style="font-size: 14px; letter-spacing: 2px;">RECEIPT</div>
<hr class="dashed"><!-- Order Info -->
<table>
<tbody>
<tr>
<td>Order #</td>
<td class="right bold">[ORDERID]</td>
</tr>
<tr>
<td>Date</td>
<td class="right">[ORDERDATE]</td>
</tr>
<tr>
<td>Status</td>
<td class="right">[ORDERSTATUS]</td>
</tr>
</tbody>
</table>
<hr class="dashed"><!-- Customer -->
<div style="font-size: 11px; color: #555; text-transform: uppercase; margin-bottom: 2px;">Customer</div>
<div>[BILLING_FIRSTNAME] [BILLING_LASTNAME]</div>
[IF:BILLING_EMAIL]
<div style="font-size: 11px;">[BILLING_EMAIL]</div>
[/IF:BILLING_EMAIL]<hr class="double-dashed"><!-- Items --> [ITEMS_LOOP] [IF:ITEM_OPTIONS] [/IF:ITEM_OPTIONS]
<table class="item-row">
<tbody>
<tr>
<td class="bold" colspan="2">[ITEM_NAME]</td>
</tr>
<tr>
<td style="font-size: 11px; color: #555; padding-left: 8px;" colspan="2">[ITEM_OPTIONS]</td>
</tr>
<tr>
<td style="padding-left: 8px;">[ITEM_QTY] x [ITEM_PRICE]</td>
<td class="right bold">[ITEM_TOTAL]</td>
</tr>
</tbody>
</table>
<hr class="dashed">[/ITEMS_LOOP] <!-- Totals --> [IF:SHIPPING_AMOUNT] [/IF:SHIPPING_AMOUNT] [IF:TAX_AMOUNT] [/IF:TAX_AMOUNT] [IF:DISCOUNT_AMOUNT] [/IF:DISCOUNT_AMOUNT]
<table class="total-row">
<tbody>
<tr>
<td>Subtotal</td>
<td class="right">[SUBTOTAL]</td>
</tr>
<tr>
<td>Shipping</td>
<td class="right">[SHIPPING_AMOUNT]</td>
</tr>
<tr>
<td>Tax</td>
<td class="right">[TAX_AMOUNT]</td>
</tr>
<tr>
<td>Discount</td>
<td class="right">-[DISCOUNT_AMOUNT]</td>
</tr>
</tbody>
</table>
<hr class="double-dashed">
<table class="grand-total">
<tbody>
<tr>
<td>TOTAL</td>
<td class="right">[ORDERAMOUNT]</td>
</tr>
</tbody>
</table>
<hr class="double-dashed"><!-- Payment --> [IF:PAYMENT_METHOD]
<table>
<tbody>
<tr>
<td>Paid via</td>
<td class="right">[PAYMENT_METHOD]</td>
</tr>
</tbody>
</table>
<hr class="dashed">[/IF:PAYMENT_METHOD] <!-- Hook --> [HOOK:AFTER_RECEIPT_BODY] <!-- Footer -->
<div class="center" style="margin-top: 12px; font-size: 13px;">Thank you for your purchase!</div>
<div class="center" style="margin-top: 8px; font-size: 10px; color: #999;">© [CURRENT_YEAR] [SITENAME]</div>
