        (4, 'Receipt (Full Page)', 'receipt', '*', '1', '*', '<!-- J2Commerce Receipt - Modern Template -->
<table style="background-color: #f8fafc; font-family: Arial, Helvetica, sans-serif;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 20px 10px;" align="center">[IF:PAYMENT_METHOD] [/IF:PAYMENT_METHOD] [HOOK:AFTER_RECEIPT_BODY]
<table class="rcpt-container" style="max-width: 600px; width: 100%; background-color: #ffffff;" border="0" width="600" cellspacing="0" cellpadding="0"><!-- Logo Bar -->
<tbody>
<tr>
<td style="padding: 20px 30px; background-color: #ffffff; border-radius: 12px 12px 0 0; text-align: center;">[IF:STORE_LOGO_URL] <img style="display: block; margin: 0 auto; border: 0; height: [LOGO_MAX_HEIGHT]px; width: auto;" alt="[SITENAME]"  src="[STORE_LOGO_URL]"> [/IF:STORE_LOGO_URL] [IFNOT:STORE_LOGO_URL] <span style="font-size: 22px; font-weight: bold; color: [accent_color];">[SITENAME]</span> [/IFNOT:STORE_LOGO_URL]</td>
</tr>
<!-- Receipt Header Banner -->
<tr>
<td style="background-color: [accent_color]; padding: 28px 30px; text-align: center;">
<table border="0" cellspacing="0" cellpadding="0" align="center">
<tbody>
<tr>
<td style="width: 50px; height: 50px; background-color: rgba(255,255,255,0.2); border-radius: 50%; text-align: center; vertical-align: middle; font-size: 24px; color: #ffffff;">✅</td>
</tr>
</tbody>
</table>
<h1 style="margin: 14px 0 4px 0; font-size: 24px; font-weight: bold; color: #ffffff; text-transform: uppercase; letter-spacing: 1px;">Receipt</h1>
<p style="margin: 0; font-size: 14px; color: rgba(255,255,255,0.85);">Order #[ORDERID] • [ORDERDATE]</p>
</td>
</tr>
<!-- Billing Info -->
<tr>
<td class="mobile-padding" style="padding: 20px 20px 0 20px;">
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Billed To</td>
</tr>
<tr>
<td style="padding: 14px 18px; font-size: 14px; color: #1f2937; line-height: 1.6;"><strong style="font-size: 15px;">[BILLING_FIRSTNAME] [BILLING_LASTNAME]</strong> [IF:BILLING_COMPANY]<br>[BILLING_COMPANY][/IF:BILLING_COMPANY]<br>[BILLING_ADDRESS_1] [IF:BILLING_ADDRESS_2]<br>[BILLING_ADDRESS_2][/IF:BILLING_ADDRESS_2]<br>[BILLING_CITY], [BILLING_STATE] [BILLING_ZIP]<br>[BILLING_COUNTRY] [IF:BILLING_EMAIL]<br>✉ [BILLING_EMAIL][/IF:BILLING_EMAIL]</td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Items Table -->
<tr>
<td class="mobile-padding" style="padding: 16px 20px;">[ITEMS_LOOP] [/ITEMS_LOOP]
<table style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 16px 20px; border-bottom: 1px solid #f3f4f6;" colspan="4"><span style="font-size: 15px; font-weight: bold; color: #1f2937;">Items Purchased</span></td>
</tr>
<tr>
<td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Product</td>
<td style="padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 50px;">Qty</td>
<td style="padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: right; width: 80px;">Price</td>
<td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: right; width: 90px;">Total</td>
</tr>
<tr>
<td style="padding: 12px 20px; border-top: 1px solid #f3f4f6; vertical-align: top;"><span style="font-size: 14px; font-weight: 600; color: #1f2937;">[ITEM_NAME]</span> [IF:ITEM_SKU]<br><span style="font-size: 12px; color: #9ca3af;">SKU: [ITEM_SKU]</span>[/IF:ITEM_SKU] [IF:ITEM_OPTIONS]<br><span style="font-size: 12px; color: #6b7280;">[ITEM_OPTIONS]</span>[/IF:ITEM_OPTIONS]</td>
<td style="padding: 12px 10px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top; font-size: 14px; color: #1f2937;">[ITEM_QTY]</td>
<td style="padding: 12px 10px; border-top: 1px solid #f3f4f6; text-align: right; vertical-align: top; font-size: 14px; color: #1f2937;">[ITEM_PRICE]</td>
<td style="padding: 12px 20px; border-top: 1px solid #f3f4f6; text-align: right; vertical-align: top; font-size: 14px; font-weight: 600; color: #1f2937;">[ITEM_TOTAL]</td>
</tr>
<!-- Totals -->
<tr>
<td style="padding: 0 20px; border-top: 2px solid #e5e7eb;" colspan="4">[IF:SHIPPING_AMOUNT] [/IF:SHIPPING_AMOUNT] [IF:TAX_AMOUNT] [/IF:TAX_AMOUNT] [IF:DISCOUNT_AMOUNT] [/IF:DISCOUNT_AMOUNT]
<table border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 10px 0; font-size: 13px; color: #6b7280;">Subtotal</td>
<td style="padding: 10px 0; font-size: 13px; color: #1f2937; text-align: right;">[SUBTOTAL]</td>
</tr>
<tr>
<td style="padding: 6px 0; font-size: 13px; color: #6b7280;">Shipping</td>
<td style="padding: 6px 0; font-size: 13px; color: #1f2937; text-align: right;">[SHIPPING_AMOUNT]</td>
</tr>
<tr>
<td style="padding: 6px 0; font-size: 13px; color: #6b7280;">Tax</td>
<td style="padding: 6px 0; font-size: 13px; color: #1f2937; text-align: right;">[TAX_AMOUNT]</td>
</tr>
<tr>
<td style="padding: 6px 0; font-size: 13px; color: #16a34a;">Discount</td>
<td style="padding: 6px 0; font-size: 13px; color: #16a34a; text-align: right;">-[DISCOUNT_AMOUNT]</td>
</tr>
<tr>
<td style="padding: 14px 0 10px 0; font-size: 16px; font-weight: bold; color: #1f2937; border-top: 1px solid #e5e7eb;">Total Paid</td>
<td style="padding: 14px 0 10px 0; font-size: 16px; font-weight: bold; color: [accent_color]; text-align: right; border-top: 1px solid #e5e7eb;">[ORDERAMOUNT]</td>
</tr>
</tbody>
</table>
</td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Payment Summary -->
<tr>
<td class="mobile-padding" style="padding: 0 20px 16px 20px;">
<table style="background-color: #ecfdf5; border: 1px solid #a7f3d0; border-radius: 10px;" border="0" width="100%" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td style="padding: 14px 18px; font-size: 14px; color: #065f46; text-align: center;">✓ <strong>Payment received</strong> via [PAYMENT_METHOD]</td>
</tr>
</tbody>
</table>
</td>
</tr>
<!-- Hook: After Receipt Body --><!-- Footer -->
<tr>
